output_file = Path("data/generated/qa_pairs_ru.json")

# Загружаем существующие пары (или начинаем с пустого списка)
existing = []
if output_file.exists():
    with open(output_file, encoding="utf-8") as f:
        existing = json.load(f)

# Добавляем новые
new_pairs = json.loads(NEW_BATCH)
combined = existing + new_pairs

# Сохраняем
with open(output_file, "w", encoding="utf-8") as f:
    json.dump(combined, f, ensure_ascii=False, indent=2)

print(
    f"Было: {len(existing)} | Добавлено: {len(new_pairs)} | Итого: {len(combined)}"
)

